    fn SetAdoptedStyleSheets(
        &self,
        context: JSContext,
        val: HandleValue,
        can_gc: CanGc,
    ) -> ErrorResult {
        let result = DocumentOrShadowRoot::set_adopted_stylesheet_from_jsval(
